def _find_converted_file(directory, expected_stem, expected_format):
    """
    Find the converted file in the output directory.
    
    LibreOffice names the output file with the same stem as input but with the new extension.
    """
    
    dir_path = Path(directory)
    
    # Try exact match first
    exact_match = dir_path / f"{expected_stem}.{expected_format}"
    if exact_match.exists():
        return exact_match
    
    # Try case-insensitive match
    for f in dir_path.iterdir():
        if f.is_file():
            if f.stem.lower() == expected_stem.lower():
                if f.suffix.lower().lstrip('.') == expected_format.lower():
                    return f
    
    # If only one file exists in the directory, return it
    files = [f for f in dir_path.iterdir() if f.is_file()]
    if len(files) == 1:
        return files[0]
    
    # Try matching just by extension
    for f in files:
        if f.suffix.lower().lstrip('.') == expected_format.lower():
            return f
    
    return None


def _get_clean_env():
    """Get a clean environment for LibreOffice execution."""
    env = os.environ.copy()
    # Ensure LibreOffice doesn't try to connect to a running instance
    # that might interfere with headless mode
    env.pop('DISPLAY', None)  # Remove DISPLAY to ensure headless mode on Linux
    return env


def batch_convert(input_files, output_dir, output_format):
    """
    Convert multiple files to a specified format.
    
    Args:
        input_files (list): List of input file paths
        output_dir (str): Directory for output files
        output_format (str): Target format
    
    Returns:
        list: List of result dictionaries for each conversion
    """
    results = []
    output_dir_path = Path(output_dir)
    output_dir_path.mkdir(parents=True, exist_ok=True)
    
    for input_file in input_files:
        input_path = Path(input_file)
        output_file = output_dir_path / f"{input_path.stem}.{output_format.lower().lstrip('.')}"
        result = convertDocument(str(input_file), str(output_file), output_format)
        result['input_file'] = str(input_file)
        results.append(result)
    
    return results


